mapper.select:
/* TM_ME32001_Dao_retrieveWtwkEltengMsrinsCndItslfFcltyNmList */ SELECT itslf_fclty_nm AS cmmn_cd, itslf_fclty_nm AS cmmn_cd_nm FROM tm_me32001 WHERE 1 = 1
AND ecs_chrg_dept_id = #{ecsChrgDeptId}
GROUP BY itslf_fclty_nm

/* TM_ME32001_Dao_retrieveWtwkEltengMsrinsList */ SELECT ( SELECT stext FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND objid = ecs_chrg_dept_id ) AS dept_nm, ecs_chrg_dept_id, itslf_fclty_nm, mnfctr_ym, mrnr_chck_hist_ym, mrnr_chck_plan_ym, elteng_msrins_idnum, mrnr_chg_need_ym, rm_ctnt, frst_regist_dt, frst_rgstr_id, last_updt_dt, last_updusr_id, updt_rsn FROM tm_me32001 WHERE 1 = 1
AND ecs_chrg_dept_id = #{ecsChrgDeptId}
AND itslf_fclty_nm = #{itslfFcltyNm}
ORDER BY ecs_chrg_dept_id, itslf_fclty_nm

mapper.delete:
/* TM_ME32001_Dao_deleteWtwkEltengMsrinsList */
DELETE FROM
	tm_me32001
WHERE
	elteng_msrins_idnum = #{eltengMsrinsIdnum}
